const input = $input.first().json;
let parsed;
if (typeof input.query === 'string') {
  try { parsed = JSON.parse(input.query); } catch (e) { parsed = input; }
} else if (input.query && typeof input.query === 'object') {
  parsed = input.query;
} else {
  parsed = input;
}
return [{ json: parsed }];

const identifier = ($('Parse Input').first().json.formula_identifier || $('Parse Input').first().json.formula_name || '').trim();
const formulas = $('Read Formulas Sheet').all();
let ingredients = [];
try { ingredients = $('Read Ingredients Sheet').all(); } catch(e) { ingredients = []; }

const formula = formulas.find(r =>
  r.json.FormulaID === identifier ||
  String(r.json.FormulaID) === identifier ||
  (r.json.Name || '').toLowerCase() === identifier.toLowerCase()
);

if (!formula) {
  return [{ json: { result: `Formula not found: "${identifier}". Use list_formulas to see available formulas.` } }];
}

const f = formula.json;
const formulaIngredients = ingredients.filter(r => String(r.json.FormulaID) === String(f.FormulaID));

let output = `=== ${f.Name} ===\n`;
output += `Category: ${f.Category} | Status: ${f.Status} | Target pH: ${f.TargetPH || 'Not set'}\n`;
output += `Total: ${f.TotalPct || '0'}% | Created: ${f.CreatedAt} | Updated: ${f.UpdatedAt}\n`;
if (f.Notes) output += `Notes: ${f.Notes}\n`;
output += `\n--- Ingredients (${formulaIngredients.length}) ---\n`;

if (formulaIngredients.length === 0) {
  output += 'No ingredients added yet.\n';
} else {
  const phases = {};
  for (const ing of formulaIngredients) {
    const phase = ing.json.Phase || 'Unassigned';
    if (!phases[phase]) phases[phase] = [];
    phases[phase].push(ing.json);
  }
  const phaseOrder = ['Water', 'Oil', 'Emulsifier', 'Active', 'Preservative', 'Fragrance', 'CoolDown', 'Unassigned'];
  for (const phase of phaseOrder) {
    if (!phases[phase]) continue;
    output += `\n[${phase} Phase]\n`;
    for (const ing of phases[phase]) {
      output += `  ${ing.IngredientName} (${ing.INCIName || '-'}) - ${ing.Percentage}%`;
      output += ` | Function: ${ing.Function || '-'}`;
      if (ing.MaxPct) output += ` | Max: ${ing.MaxPct}%`;
      output += '\n';
    }
  }
  const totalPct = formulaIngredients.reduce((sum, ing) => sum + parseFloat(ing.json.Percentage || 0), 0);
  output += `\nTotal: ${totalPct.toFixed(1)}%`;
  if (Math.abs(totalPct - 100) > 0.1) {
    output += ` *** WARNING: Total is not 100%! ***`;
  }
}

return [{ json: { result: output } }];
